const cfg = $('Set API and Search Parameters').first().json;
const maxVideos = Math.max(1, Number(cfg.maxVideos || 1));
const token = cfg.token;
const baseUrl = cfg.baseUrl;
const keyword = cfg.keyword;

function firstUrl(value) {
  if (value && Array.isArray(value.url_list) && value.url_list.length > 0) {
    return value.url_list[0];
  }
  return '';
}

function getSearchRoot(input) {
  if (Array.isArray(input)) return input[0] || {};
  return input || {};
}

const rawSearchResponse = getSearchRoot($input.first().json);
const searchData = rawSearchResponse.data || {};
const businessData = Array.isArray(searchData.business_data) ? searchData.business_data : [];

const candidates = [];

for (const entry of businessData) {
  const aweme = entry?.data?.aweme_info;
  if (!aweme || !aweme.aweme_id) continue;

  candidates.push({
    videoId: String(aweme.aweme_id),
    dataId: entry.data_id ?? '',
    providerDocIdStr: entry?.data?.provider_doc_id_str ? String(entry.data.provider_doc_id_str) : '',
    searchId: entry?.log?.search_id || entry?.data?.log_data?.search_id || '',
    desc: aweme.desc || '',
    itemTitle: aweme.item_title || '',
    caption: aweme.caption || '',
    createTime: aweme.create_time || null,
    shareUrl: aweme.share_url || aweme.share_info?.share_url || '',
    author: {
      uid: aweme.author?.uid ? String(aweme.author.uid) : '',
      secUid: aweme.author?.sec_uid || '',
      nickname: aweme.author?.nickname || '',
      uniqueId: aweme.author?.unique_id || '',
      signature: aweme.author?.signature || '',
      followerCount: aweme.author?.follower_count ?? null,
      avatarUrl: firstUrl(aweme.author?.avatar_thumb)
    },
    statistics: {
      diggCount: aweme.statistics?.digg_count ?? null,
      commentCount: aweme.statistics?.comment_count ?? null,
      shareCount: aweme.statistics?.share_count ?? null,
      collectCount: aweme.statistics?.collect_count ?? null,
      downloadCount: aweme.statistics?.download_count ?? null,
      playCount: aweme.statistics?.play_count ?? null
    },
    video: {
      durationMs: aweme.video?.duration ?? aweme.duration ?? null,
      coverUrl: firstUrl(aweme.video?.cover),
      playUrl: firstUrl(aweme.video?.play_addr),
      downloadUrl: firstUrl(aweme.video?.download_addr)
    },
    hashtags: Array.isArray(aweme.text_extra)
      ? aweme.text_extra.map(tag => ({
          hashtagName: tag.hashtag_name || '',
          hashtagId: tag.hashtag_id ? String(tag.hashtag_id) : ''
        })).filter(tag => tag.hashtagName || tag.hashtagId)
      : []
  });
}

const selected = candidates.slice(0, maxVideos);

if (selected.length === 0) {
  return [{
    json: {
      baseUrl,
      token,
      keyword,
      videoId: '',
      videoRank: null,
      selectedBy: 'data.business_data[].data.aweme_info.aweme_id',
      error: 'No video ID found in data.business_data[].data.aweme_info.aweme_id.',
      searchSummary: {
        keyword: searchData.business_config?.keyword || keyword,
        hasMore: searchData.business_config?.has_more ?? null,
        cardCount: searchData.business_config?.card_count ?? null,
        nextPage: searchData.business_config?.next_page || null,
        searchId: searchData.business_config?.next_page?.search_id || searchData.log?.search_id || ''
      },
      searchCandidates: [],
      rawSearchResponse
    }
  }];
}

return selected.map((candidate, index) => ({
  json: {
    baseUrl,
    token,
    keyword,
    videoId: candidate.videoId,
    videoRank: index + 1,
    selectedBy: 'data.business_data[].data.aweme_info.aweme_id',
    selectedSearchVideo: candidate,
    searchSummary: {
      keyword: searchData.business_config?.keyword || keyword,
      hasMore: searchData.business_config?.has_more ?? null,
      cardCount: searchData.business_config?.card_count ?? null,
      nextPage: searchData.business_config?.next_page || null,
      searchId: searchData.business_config?.next_page?.search_id || searchData.log?.search_id || candidate.searchId || ''
    },
    searchCandidates: candidates,
    rawSearchResponse
  }
}));

function firstUrl(value) {
  if (value && Array.isArray(value.url_list) && value.url_list.length > 0) {
    return value.url_list[0];
  }
  return '';
}

function safeParseJson(value) {
  if (typeof value !== 'string' || value.trim() === '') return null;
  try {
    return JSON.parse(value);
  } catch (error) {
    return value;
  }
}

function cleanHashtags(textExtra) {
  if (!Array.isArray(textExtra)) return [];
  return textExtra
    .map(tag => ({
      hashtagName: tag.hashtag_name || '',
      hashtagId: tag.hashtag_id ? String(tag.hashtag_id) : '',
      type: tag.type ?? null
    }))
    .filter(tag => tag.hashtagName || tag.hashtagId);
}

function cleanChallenges(chaList) {
  if (!Array.isArray(chaList)) return [];
  return chaList
    .map(challenge => ({
      challengeId: challenge.cid ? String(challenge.cid) : '',
      challengeName: challenge.cha_name || '',
      schema: challenge.schema || '',
      shareUrl: challenge.share_info?.share_url || ''
    }))
    .filter(challenge => challenge.challengeName || challenge.challengeId);
}

function cleanVideoTags(videoTags) {
  if (!Array.isArray(videoTags)) return [];
  return videoTags.map(tag => ({
    tagId: tag.tag_id ?? null,
    tagName: tag.tag_name || '',
    level: tag.level ?? null
  }));
}

function cleanDetail(rawDetailResponse, extracted) {
  const detailData = rawDetailResponse.data || {};
  const aweme = detailData.aweme_detail || {};

  return {
    videoId: aweme.aweme_id ? String(aweme.aweme_id) : extracted.videoId || '',
    groupId: aweme.group_id ? String(aweme.group_id) : '',
    secItemId: aweme.sec_item_id || '',
    desc: aweme.desc || '',
    itemTitle: aweme.item_title || '',
    caption: aweme.caption || '',
    previewTitle: aweme.preview_title || '',
    createTime: aweme.create_time || null,
    durationMs: aweme.duration ?? aweme.video?.duration ?? null,
    shareUrl: aweme.share_url || aweme.share_info?.share_url || '',
    mediaType: aweme.media_type ?? null,
    awemeType: aweme.aweme_type ?? null,
    region: aweme.region || '',
    city: aweme.city || '',
    author: {
      uid: aweme.author?.uid ? String(aweme.author.uid) : '',
      secUid: aweme.author?.sec_uid || '',
      shortId: aweme.author?.short_id || '',
      uniqueId: aweme.author?.unique_id || '',
      nickname: aweme.author?.nickname || '',
      signature: aweme.author?.signature || '',
      gender: aweme.author?.gender ?? null,
      isVerified: aweme.author?.is_verified ?? null,
      followerCount: aweme.author?.follower_count ?? null,
      followingCount: aweme.author?.following_count ?? null,
      awemeCount: aweme.author?.aweme_count ?? null,
      totalFavorited: aweme.author?.total_favorited ?? null,
      avatarThumbUrl: firstUrl(aweme.author?.avatar_thumb),
      avatarMediumUrl: firstUrl(aweme.author?.avatar_medium),
      avatarLargerUrl: firstUrl(aweme.author?.avatar_larger)
    },
    statistics: {
      awemeId: aweme.statistics?.aweme_id ? String(aweme.statistics.aweme_id) : '',
      diggCount: aweme.statistics?.digg_count ?? null,
      commentCount: aweme.statistics?.comment_count ?? null,
      shareCount: aweme.statistics?.share_count ?? null,
      collectCount: aweme.statistics?.collect_count ?? null,
      downloadCount: aweme.statistics?.download_count ?? null,
      playCount: aweme.statistics?.play_count ?? null,
      forwardCount: aweme.statistics?.forward_count ?? null
    },
    status: {
      statusCode: detailData.status_code ?? null,
      isDelete: aweme.status?.is_delete ?? null,
      isPrivate: aweme.status?.is_private ?? null,
      allowShare: aweme.status?.allow_share ?? null,
      allowComment: aweme.status?.allow_comment ?? null,
      downloadStatus: aweme.status?.download_status ?? null,
      reviewed: aweme.status?.reviewed ?? null,
      listenVideoStatus: aweme.status?.listen_video_status ?? null
    },
    videoControl: {
      allowDownload: aweme.video_control?.allow_download ?? null,
      allowShare: aweme.video_control?.allow_share ?? null,
      allowDuet: aweme.video_control?.allow_duet ?? null,
      allowReact: aweme.video_control?.allow_react ?? null,
      allowStitch: aweme.video_control?.allow_stitch ?? null,
      preventDownloadType: aweme.video_control?.prevent_download_type ?? null,
      downloadFailInfo: aweme.video_control?.download_info?.fail_info || null
    },
    video: {
      coverUrl: firstUrl(aweme.video?.cover),
      originCoverUrl: firstUrl(aweme.video?.origin_cover),
      dynamicCoverUrl: firstUrl(aweme.video?.dynamic_cover),
      playUrl: firstUrl(aweme.video?.play_addr),
      playH264Url: firstUrl(aweme.video?.play_addr_h264),
      play265Url: firstUrl(aweme.video?.play_addr_265),
      downloadUrl: firstUrl(aweme.video?.download_addr),
      ratio: aweme.video?.ratio || '',
      format: aweme.video?.format || '',
      width: aweme.video?.width ?? null,
      height: aweme.video?.height ?? null,
      durationMs: aweme.video?.duration ?? null,
      hasWatermark: aweme.video?.has_watermark ?? null,
      cdnUrlExpired: aweme.video?.cdn_url_expired ?? null
    },
    music: {
      id: aweme.music?.id_str || (aweme.music?.id ? String(aweme.music.id) : ''),
      title: aweme.music?.title || '',
      author: aweme.music?.author || '',
      ownerId: aweme.music?.owner_id ? String(aweme.music.owner_id) : '',
      ownerNickname: aweme.music?.owner_nickname || '',
      duration: aweme.music?.duration ?? null,
      playUrl: firstUrl(aweme.music?.play_url),
      coverUrl: firstUrl(aweme.music?.cover_thumb),
      extra: safeParseJson(aweme.music?.extra)
    },
    hashtags: cleanHashtags(aweme.text_extra),
    challenges: cleanChallenges(aweme.cha_list),
    videoTags: cleanVideoTags(aweme.video_tag),
    rawJsonStringFields: {
      miscInfo: safeParseJson(aweme.misc_info),
      componentInfoV2: safeParseJson(aweme.component_info_v2),
      feedCommentCommonFlags: safeParseJson(aweme.feed_comment_config?.common_flags),
      entertainmentRecommendInfo: safeParseJson(aweme.entertainment_recommend_info),
      commonBarInfo: safeParseJson(aweme.common_bar_info)
    }
  };
}

const extracted = $('Extract Video IDs from Search').first().json || {};
const rows = $input.all();

return rows.map(item => {
  const rawDetailResponse = item.json || {};
  const cleanedDetail = cleanDetail(rawDetailResponse, extracted);

  return {
    json: {
      workflowStage: 'real-response-mapped-output',
      requestedKeyword: extracted.keyword || $('Set API and Search Parameters').first().json.keyword || '',
      requestedVideoId: extracted.videoId || '',
      selectedVideoRank: extracted.videoRank || 1,
      main: {
        videoDetail: cleanedDetail
      },
      auxiliary: {
        selectedSearchVideo: extracted.selectedSearchVideo || null,
        searchSummary: extracted.searchSummary || null,
        searchCandidates: extracted.searchCandidates || []
      },
      raw: {
        searchResponse: extracted.rawSearchResponse || {},
        detailResponse: rawDetailResponse
      }
    }
  };
});
